package com.customminecraftserver.bedrock;

import io.netty.buffer.ByteBufUtil;

final class BedrockStartGameTemplates {
    private static final byte[] START_GAME_TEMPLATE_898 = ByteBufUtil.decodeHexDump(
            ""
    );
    private static final byte[] START_GAME_TEMPLATE_944 = ByteBufUtil.decodeHexDump(
            ""
    );

    private BedrockStartGameTemplates() {
    }

    static byte[] startGameTemplate(int protocolVersion) {
        return protocolVersion < 924 ? START_GAME_TEMPLATE_898 : START_GAME_TEMPLATE_944;
    }
}
